// Gera links de afiliado do Mercado Livre em lote, via a API interna usada pelo Linkbuilder
// (mercadolivre.com.br/afiliados/linkbuilder#hub). Descoberta manualmente via DevTools em
// 2026-07-14 — não é uma API pública documentada, pode mudar sem aviso.
//
// Autenticação por SESSÃO DE NAVEGADOR (cookie + CSRF token), não um token de API estável — os
// dois valores abaixo precisam ser atualizados periodicamente quando a sessão expirar: abre o
// Linkbuilder logado, DevTools > Network > Fetch/XHR, gera um link de teste, acha a chamada
// "createLink", copia o header Cookie e o header X-Csrf-Token de novo.
// NUNCA commitar os valores reais aqui — só editar direto neste node, na instância do n8n.
const ML_COOKIE = 'COLE_SEU_COOKIE_AQUI';
const ML_CSRF_TOKEN = 'COLE_SEU_CSRF_TOKEN_AQUI';
const ML_AFFILIATE_TAG = 'promodasqueridas';

const items = $input.all();
const mlItems = items.filter(i => i.json.platform === 'ml');

const affiliateMap = {};
if (mlItems.length > 0) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://www.mercadolivre.com.br/affiliate-program/api/v2/affiliates/createLink',
      headers: {
        'Content-Type': 'application/json',
        'Cookie': ML_COOKIE,
        'X-Csrf-Token': ML_CSRF_TOKEN,
      },
      body: {
        urls: mlItems.map(i => i.json.product_url),
        tag: ML_AFFILIATE_TAG,
      },
      json: true,
    });

    for (const entry of (response.urls || [])) {
      if (entry.created && entry.short_url) {
        affiliateMap[entry.origin_url] = entry.short_url;
      }
    }
  } catch (e) {
    // Falha na geração de link (sessão expirada, etc.) — segue sem link de afiliado ML nessa
    // rodada, em vez de travar a postagem inteira.
  }
}

return items.map(item => ({
  json: {
    ...item.json,
    ml_affiliate_url: affiliateMap[item.json.product_url] || null,
  },
}));

// Geração de link de afiliado por plataforma.
// Amazon: concatena a tag na URL do produto.
// Mercado Livre: usa o link já gerado em lote pelo node "Gerar Links Afiliados ML" (campo
// ml_affiliate_url). Se vier null (sessão do ML expirada ou item não coberto), cai pra URL normal
// do produto em vez de travar a postagem inteira.
const item = $json;
let affiliateUrl;

if (item.platform === 'amazon') {
  const sep = item.product_url.includes('?') ? '&' : '?';
  affiliateUrl = `${item.product_url}${sep}tag=${$('Config').first().json.amazonAffiliateTag}`;
} else {
  affiliateUrl = item.ml_affiliate_url || item.product_url;
}

const storeName = item.platform === 'amazon' ? 'Amazon' : 'Mercado Livre';
const emoji = item.discount_pct >= 40 ? '🔥🔥' : '🔥';

let caption = `${emoji} *${item.product_name}*\n\n`;
caption += `De ~R$ ${Number(item.original_price).toFixed(2).replace('.', ',')}~\n`;
caption += `Por *R$ ${Number(item.current_price).toFixed(2).replace('.', ',')}* 🔥 (-${Math.round(item.discount_pct)}%)\n\n`;
if (item.coupon_code) {
  caption += `🎟️ Cupom: ${item.coupon_code}\n\n`;
}
caption += `👉 Pegar promoção: ${affiliateUrl}\n\n`;
caption += `🛒 ${storeName}`;

return [{ json: { ...item, affiliate_url: affiliateUrl, caption } }];
